import { useState, useEffect } from 'react';
import axiosInstance from '../axiosConfig';
import EventForm from '../components/EventForm';
import EventList from '../components/EventList';
import { useAuth } from '../context/AuthContext';

const Events = () => {
  const { user } = useAuth();
  const [events, setEvents] = useState([]);
  const [editingEvent, setEditingEvent] = useState(null);
  const [filter, setFilter] = useState('All'); // UserStory 2: Filtering function

  // Categories for filtering based on Figma design-UserStory 2
  const categories = [
    'All',
    'Outdoor & Adventure',
    'Technology',
    'Health & Wellness',
    'Food & Drink',
    'Arts & Culture'
  ];

  useEffect(() => {
    const fetchEvents = async () => {
      try {
        const response = await axiosInstance.get('/api/events');
        setEvents(response.data);
      } catch (error) {
        console.error('Failed to fetch events.');
      }
    };
    fetchEvents();
  }, []);

  // UserStory 2: Filtering logic
  const filteredEvents = filter === 'All'
    ? events
    : events.filter(e => e.category === filter);

  return (
    <div className="container mx-auto p-6 bg-gray-50 min-h-screen">
      <header className="mb-10 text-center">
        <h1 className="text-4xl font-extrabold text-green-700 mb-2">Discover Local Events</h1>
        <p className="text-gray-600">Connect with people who share the same interests.Find events, join groups, and build life long relationships.</p>
      </header>


      <div className="flex flex-wrap justify-center gap-3 mb-10">
        {categories.map(cat => (
          <button
            key={cat}
            onClick={() => setFilter(cat)}
            className={`px-5 py-2 rounded-full text-sm font-bold transition duration-300 shadow-sm ${filter === cat
              ? 'bg-green-600 text-white shadow-md scale-105'
              : 'bg-white text-green-600 border border-green-600 hover:bg-green-50'
              }`}
          >
            {cat}
          </button>
        ))}
      </div>

      {/* Logged in user only (User Story 1) */}
      {user && (
        <div className="mb-12 max-w-2xl mx-auto">
          <EventForm
            events={events}
            setEvents={setEvents}
            editingEvent={editingEvent}
            setEditingEvent={setEditingEvent}
          />
        </div>
      )}

      {/* Events grid List - UserStory 2, 8 */}
      <div className="mt-8">
        <h2 className="text-2xl font-bold text-gray-800 mb-6 border-l-4 border-green-600 pl-4">
          {filter === 'All' ? 'Featured Events' : `${filter} Events`}
        </h2>
        <EventList
          events={filteredEvents}
          setEvents={setEvents}
          setEditingEvent={setEditingEvent}
        />
      </div>
    </div>
  );
};

export default Events;
